@@ -800,12 +800,34 @@ pub const Scheduler = struct {
                         const rejected = spec_tokens.len - i;
                         const rollback_from: i32 = @intCast(cell.pos - rejected);

+                        // =========================================================
+                        // 🔙 ROLLBACK: Remove "Bad Future" from KV caches
+                        // =========================================================
+                        // When speculative decoding rejects tokens, both the main
+                        // model and draft model have computed KV cache entries for
+                        // invalid futures. We must explicitly remove them.
+
+                        // Rollback Main Model KV cache
                         const memory = c.llama_get_memory(self.ctx);
                         if (memory != null) {
                             _ = c.llama_memory_seq_rm(memory, @intCast(cell.id), rollback_from, -1);
                         }

+                        // Rollback Draft Model KV cache (critical for position sync!)
+                        if (self.draft_ctx) |draft_ctx| {
+                            const draft_memory = c.llama_get_memory(draft_ctx);
+                            if (draft_memory != null) {
+                                _ = c.llama_memory_seq_rm(draft_memory, @intCast(cell.id), rollback_from, -1);
+                            }
+                        }
+
                         cell.pos -= @intCast(rejected);
+                        logger.debug("Cell {} rollback: rejected {} tokens, pos {} -> {}", .{
+                            cell.id,
+                            rejected,
+                            cell.pos + @as(u32, @intCast(rejected)),
+                            cell.pos,
+                        });
                         break;
                     }
                 }
